(function alignBlogDataStructure() {
  const baseDate = new Date('2026-03-01T00:00:00');

  window.BLOG_DATA = window.BLOG_DATA.map((article, index) => {
    const fallbackDate = new Date(baseDate);
    fallbackDate.setDate(baseDate.getDate() - index);

    const image = typeof article.image === 'string' && article.image.trim()
      ? article.image.trim()
      : 'assets/images/cars/default.jpg';

    const readTime = typeof article.readTime === 'number'
      ? `${article.readTime} phút đọc`
      : (article.readTime || '');

    return {
      id: article.id,
      slug: article.slug,
      title: article.title,
      category: article.category,
      categoryLabel: article.categoryLabel,
      description: article.description || '',
      date: article.date || fallbackDate.toISOString().slice(0, 10),
      readTime,
      image,
      tags: Array.isArray(article.tags) ? article.tags : [],
      content: article.content || ''
    };
  });
})();